1	import { getLanguage } from '@common/utils/localStorage.ts'
2	import { LanguageEnum } from '@common/constants/language.ts'
3	import { translationStorageKey } from '@common/constants/localStorageKey'
4	import { useEffect, useState, useMemo } from 'react'
5	import _ from 'lodash'
6	
7	interface TranslationDetailResponse {
8	  english: object
9	  arabic: object
10	}
11	const useLocaleTranslation = () => {
12	  const isLanguageAR = getLanguage() === LanguageEnum.AR
13	  const [enTranslateObj, setEnTranslateObj] = useState({})
14	  const [arTranslateObj, setArTranslateObj] = useState({})
15	  const [loaded, setLoaded] = useState(false) // 新增：翻译数据加载状态
16	
17	  const getLocalStorageData = (
18	    translationStorageKey: string,
19	  ): TranslationDetailResponse | null => {
20	    try {
21	      const data = localStorage.getItem(translationStorageKey)
22	      return data ? JSON.parse(data) : null
23	    } catch (e) {
24	      console.error('Failed to parse localStorage data:', e)
25	      return null
26	    }
27	  }
28	
29	  useEffect(() => {
30	    const translateObjData = getLocalStorageData(translationStorageKey)
31	    if (translateObjData) {
32	      setEnTranslateObj(translateObjData['english'] || {})
33	      setArTranslateObj(translateObjData['arabic'] || {})
34	    }
35	    setLoaded(true)
36	  }, [])
37	
38	  // optimize caching with useMemo
39	  const currentTranslateObj = useMemo(
40	    () => (isLanguageAR ? arTranslateObj : enTranslateObj),
41	    [isLanguageAR, arTranslateObj, enTranslateObj],
42	  )
43	
44	  const replacePlaceholders = (templateString, values) => {
45	    return templateString.replace(/{{([^}]*)}}/g, (match, p1) => {
46	      // match 是整个匹配到的占位符，比如 "{{weight}}"
47	      // p1 是括号内捕获的内容，即占位符中的键名，比如 "weight"
48	      return values[p1] !== undefined ? values[p1] : match // 如果对象中有对应的值，则返回该值；否则返回原占位符
49	    })
50	  }
51	  // translation Functions
52	  const t = (key: string, replaceValue: object = {}): string => {
53	    if (!_.isObject(replaceValue)) {
54	      replaceValue = {}
55	    }
56	
57	    const translation = currentTranslateObj[key] ?? key
58	    return _.isEmpty(replaceValue)
59	      ? translation
60	      : replacePlaceholders(translation, replaceValue)
61	  }
62	
63	  return { t, loaded }
64	}
65	
66	export default useLocaleTranslation
